import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { Database } from '../../src/utils/database.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../../src/events/event-types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

/**
 * Integration tests for the full notification pipeline:
 * EventBus → NotificationService → Adapters (email/sms/webhook) → Preferences → History
 */
describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;

  // Transports for inspecting what was actually "sent"
  let emailTransport: InMemoryTransport;
  let smsTransport: InMemorySmsTransport;
  let webhookTransport: InMemoryWebhookTransport;

  // Adapters
  let emailAdapter: EmailAdapter;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;

  // Test fixtures
  const testUser: User = {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2026-01-01'),
    updatedAt: new Date('2026-01-01'),
  };

  const testOrder: Order = {
    id: 'order-100',
    userId: 'user-1',
    items: [
      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
    ],
    total: 45,
    status: 'pending',
    createdAt: new Date('2026-01-15'),
    updatedAt: new Date('2026-01-15'),
  };

  beforeEach(() => {
    // Reset all ID counters
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetLogIdCounter();

    // Fresh database and event bus
    db = new Database();
    eventBus = new EventBus();

    // Create transports
    emailTransport = new InMemoryTransport();
    smsTransport = new InMemorySmsTransport();
    webhookTransport = new InMemoryWebhookTransport();

    // Create adapters with in-memory transports
    emailAdapter = new EmailAdapter({ transport: emailTransport });
    smsAdapter = new SmsAdapter({ transport: smsTransport });
    webhookAdapter = new WebhookAdapter({
      url: 'https://hooks.example.com/notify',
      secret: 'test-secret',
      transport: webhookTransport,
    });

    // Wire up the full pipeline
    notificationService = new NotificationService(eventBus);
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);

    // Preferences
    const preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);

    // History
    const logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    notificationService.setHistoryService(historyService);
  });

  describe('Email channel end-to-end', () => {
    it('should deliver email when user has email enabled', async () => {
      // User with default preferences (email enabled)
      preferencesService.createPreferences({ userId: 'user-1' });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Verify email was sent through the transport
      const sentEmails = emailTransport.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.to).toBe('alice@example.com');
      expect(sentEmails[0]!.subject).toContain('Order Confirmation');

      // Verify notification recorded in service
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.status).toBe('sent');
      expect(notifications[0]!.channel).toBe('email');
    });

    it('should deliver welcome email via user:created event', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const sentEmails = emailTransport.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.subject).toBe('Welcome to TaskFlow Pro');
      expect(sentEmails[0]!.html).toContain('Welcome to TaskFlow Pro!');

      const notifications = notificationService.getNotifications();
      expect(notifications[0]!.type).toBe('welcome');
      expect(notifications[0]!.status).toBe('sent');
    });

    it('should deliver order status update email', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: { ...testOrder, status: 'shipped' },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const sentEmails = emailTransport.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.subject).toContain('Order Update');
    });
  });

  describe('SMS channel end-to-end', () => {
    it('should deliver SMS when user has SMS enabled', async () => {
      // Create preferences with SMS opted in
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: { enabled: true },
      });

      // Dispatch directly (SMS needs phone number as recipient)
      const result = await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'sms',
        type: 'order_confirmation',
        metadata: { userId: 'user-1', orderId: 'order-100' },
      });

      expect(result.success).toBe(true);

      const sentMessages = smsTransport.getSentMessages();
      expect(sentMessages).toHaveLength(1);
      expect(sentMessages[0]!.to).toBe('+15551234567');
      expect(sentMessages[0]!.body).toContain('order-100');

      const notifications = notificationService.getNotifications();
      expect(notifications[0]!.status).toBe('sent');
      expect(notifications[0]!.channel).toBe('sms');
    });

    it('should reject SMS with invalid phone number', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: { enabled: true },
      });

      const result = await notificationService.dispatch({
        recipient: 'not-a-phone',
        subject: 'Test',
        body: 'Test',
        channel: 'sms',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(smsTransport.getSentMessages()).toHaveLength(0);
    });
  });

  describe('Webhook channel end-to-end', () => {
    it('should deliver webhook notification', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true },
      });

      const result = await notificationService.dispatch({
        recipient: 'user-1',
        subject: 'Order Confirmed',
        body: 'Your order has been confirmed.',
        channel: 'webhook',
        type: 'order_confirmation',
        metadata: { userId: 'user-1', orderId: 'order-100' },
      });

      expect(result.success).toBe(true);

      const requests = webhookTransport.getRequests();
      expect(requests).toHaveLength(1);
      expect(requests[0]!.url).toBe('https://hooks.example.com/notify');
      expect(requests[0]!.headers['X-Webhook-Secret']).toBe('test-secret');
      expect(requests[0]!.body.type).toBe('order_confirmation');
      expect(requests[0]!.body.recipient).toBe('user-1');
      expect(requests[0]!.body.metadata?.orderId).toBe('order-100');
    });
  });

  describe('History logging', () => {
    it('should log successful email delivery in history', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      await eventBus.emit({
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('sent');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.type).toBe('order_confirmation');
      expect(logs[0]!.notificationId).toBe('notif-0001');
    });

    it('should log suppressed notification in history', async () => {
      // Email disabled
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit({
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      } as UserCreatedEvent);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('failed');
      expect(logs[0]!.error).toContain('Suppressed by user preferences');
    });

    it('should log notifications across multiple channels in history', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      // Send one on each channel
      await notificationService.dispatch({
        recipient: 'alice@example.com',
        subject: 'Email Test',
        body: 'email body',
        channel: 'email',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'SMS Test',
        body: 'sms body',
        channel: 'sms',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      await notificationService.dispatch({
        recipient: 'user-1',
        subject: 'Webhook Test',
        body: 'webhook body',
        channel: 'webhook',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(3);

      const channels = logs.map((l) => l.channel).sort();
      expect(channels).toEqual(['email', 'sms', 'webhook']);

      // Verify history can be queried by channel
      const emailLogs = historyService.query({ channel: 'email' });
      expect(emailLogs).toHaveLength(1);
      expect(emailLogs[0]!.recipient).toBe('alice@example.com');

      const smsLogs = historyService.query({ channel: 'sms' });
      expect(smsLogs).toHaveLength(1);
      expect(smsLogs[0]!.recipient).toBe('+15551234567');
    });

    it('should support querying history by type and status', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      // Send two different types
      await eventBus.emit({
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      await eventBus.emit({
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      } as UserCreatedEvent);

      const allLogs = historyService.getAll();
      expect(allLogs).toHaveLength(2);

      const orderLogs = historyService.query({ type: 'order_confirmation' });
      expect(orderLogs).toHaveLength(1);

      const sentLogs = historyService.query({ status: 'sent' });
      expect(sentLogs).toHaveLength(2);
    });
  });

  describe('Preferences enforcement', () => {
    it('should not send email when email is disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit({
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      // Email should NOT have been sent
      expect(emailTransport.getSentEmails()).toHaveLength(0);

      // But the notification should be recorded as failed/suppressed
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.status).toBe('failed');
    });

    it('should not send SMS when SMS is disabled (default)', async () => {
      // Default preferences: SMS is disabled
      preferencesService.createPreferences({ userId: 'user-1' });

      const result = await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test body',
        channel: 'sms',
        type: 'order_confirmation',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Suppressed by user preferences');
      expect(smsTransport.getSentMessages()).toHaveLength(0);
    });

    it('should not send webhook when webhook is disabled (default)', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      const result = await notificationService.dispatch({
        recipient: 'user-1',
        subject: 'Test',
        body: 'Test body',
        channel: 'webhook',
        type: 'order_confirmation',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Suppressed by user preferences');
      expect(webhookTransport.getRequests()).toHaveLength(0);
    });

    it('should respect category-level filtering', async () => {
      // Only subscribe to welcome emails, not order notifications
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          subscribedCategories: ['welcome'],
        },
      });

      // Order notification should be suppressed
      await eventBus.emit({
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(emailTransport.getSentEmails()).toHaveLength(0);
      expect(notificationService.getNotifications()[0]!.status).toBe('failed');

      // Welcome notification should go through
      await eventBus.emit({
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      } as UserCreatedEvent);

      expect(emailTransport.getSentEmails()).toHaveLength(1);
      expect(notificationService.getNotifications()[1]!.status).toBe('sent');
    });

    it('should send all notifications when no preferences exist', async () => {
      // No preferences created — email defaults to sending
      await eventBus.emit({
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(emailTransport.getSentEmails()).toHaveLength(1);
      expect(notificationService.getNotifications()[0]!.status).toBe('sent');
    });

    it('should not send SMS when no preferences exist (opt-in channel)', async () => {
      // No preferences — SMS defaults to not sending
      const result = await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test',
        channel: 'sms',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(false);
      expect(smsTransport.getSentMessages()).toHaveLength(0);
    });

    it('should allow enabling a previously disabled channel via update', async () => {
      preferencesService.createPreferences({ userId: 'user-1' }); // SMS disabled by default

      // SMS should be suppressed
      let result = await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test',
        channel: 'sms',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });
      expect(result.success).toBe(false);

      // Enable SMS
      preferencesService.updatePreferences('user-1', {
        sms: { enabled: true },
      });

      // Now SMS should go through
      result = await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Test 2',
        body: 'Test 2',
        channel: 'sms',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });
      expect(result.success).toBe(true);
      expect(smsTransport.getSentMessages()).toHaveLength(1);
    });
