  describe('Notification ordering', () => {
    it('should maintain order for same-recipient notifications across the full pipeline', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      // Emit multiple events rapidly for the same user
      const event1: OrderCreatedEvent = {
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      };

      const event2: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: { ...testOrder, status: 'confirmed' },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      const event3: UserCreatedEvent = {
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      };

      // Emit all events sequentially (EventBus awaits handlers)
      await eventBus.emit(event1);
      await eventBus.emit(event2);
      await eventBus.emit(event3);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(3);

      // Verify order: order_confirmation, order_status_update, welcome
      expect(notifications[0]!.type).toBe('order_confirmation');
      expect(notifications[1]!.type).toBe('order_status_update');
      expect(notifications[2]!.type).toBe('welcome');

      // Verify IDs are sequential
      expect(notifications[0]!.id).toBe('notif-0001');
      expect(notifications[1]!.id).toBe('notif-0002');
      expect(notifications[2]!.id).toBe('notif-0003');

      // History should match the same order
      const logs = historyService.getAll();
      expect(logs).toHaveLength(3);
      expect(logs[0]!.notificationId).toBe('notif-0001');
      expect(logs[1]!.notificationId).toBe('notif-0002');
      expect(logs[2]!.notificationId).toBe('notif-0003');
