      const p2 = notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Second',
        body: 'Second notification',
        channel: 'sms',
        type: 'order_status_update',
        metadata: { userId: 'user-1' },
      });
      const p3 = notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Third',
        body: 'Third notification',
        channel: 'sms',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      const results = await Promise.all([p1, p2, p3]);
      expect(results.every((r) => r.success)).toBe(true);

      const sentMessages = smsTransport.getSentMessages();
      expect(sentMessages).toHaveLength(3);
      expect(sentMessages[0]!.body).toContain('First');
      expect(sentMessages[1]!.body).toContain('Second');
      expect(sentMessages[2]!.body).toContain('Third');
    });
  });

  describe('Multi-channel pipeline', () => {
