      const smsResult = await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Order Confirmed',
        body: 'Your order is confirmed.',
        channel: 'sms',
        type: 'order_confirmation',
        metadata: { userId: 'user-1', orderId: 'order-100' },
      });

      const webhookResult = await notificationService.dispatch({
        recipient: 'user-1',
        subject: 'Order Confirmed',
        body: 'Your order is confirmed.',
        channel: 'webhook',
        type: 'order_confirmation',
        metadata: { userId: 'user-1', orderId: 'order-100' },
      });

      expect(emailResult.success).toBe(true);
      expect(smsResult.success).toBe(true);
      expect(webhookResult.success).toBe(true);

      // Each transport should have received exactly one message
      expect(emailTransport.getSentEmails()).toHaveLength(1);
      expect(smsTransport.getSentMessages()).toHaveLength(1);
      expect(webhookTransport.getRequests()).toHaveLength(1);

      // History should show all three
      expect(historyService.count()).toBe(3);
    });

    it('should selectively deliver based on per-channel preferences', async () => {
      // Email enabled, SMS enabled, webhook disabled
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: false },
      });

      await notificationService.dispatch({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        channel: 'email',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      await notificationService.dispatch({
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test',
        channel: 'sms',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      await notificationService.dispatch({
        recipient: 'user-1',
        subject: 'Test',
        body: 'Test',
        channel: 'webhook',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      expect(emailTransport.getSentEmails()).toHaveLength(1);
      expect(smsTransport.getSentMessages()).toHaveLength(1);
      expect(webhookTransport.getRequests()).toHaveLength(0); // suppressed

      const logs = historyService.getAll();
      const webhookLog = logs.find((l) => l.channel === 'webhook');
      expect(webhookLog!.status).toBe('failed');
      expect(webhookLog!.error).toContain('Suppressed');
    });
  });

  describe('Error handling in pipeline', () => {
    it('should handle missing adapter gracefully and log to history', async () => {
      // Create service without registering in_app adapter
      const result = await notificationService.dispatch({
        recipient: 'user-1',
        subject: 'In-app test',
        body: 'Test body',
        channel: 'in_app',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('No adapter for channel');

      // History should record the failure
      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('failed');
    });

    it('should continue pipeline after adapter failure', async () => {
      preferencesService.createPreferences({ userId: 'user-1' });

      // First dispatch: valid email
      await notificationService.dispatch({
        recipient: 'alice@example.com',
        subject: 'Valid',
        body: 'Valid body',
        channel: 'email',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      // Second dispatch: invalid email (adapter will reject)
      await notificationService.dispatch({
        recipient: 'not-an-email',
        subject: 'Invalid',
        body: 'Invalid body',
        channel: 'email',
        type: 'welcome',
        metadata: { userId: 'user-1' },
      });

      // Third dispatch: valid email again
      await notificationService.dispatch({
        recipient: 'alice@example.com',
        subject: 'Also Valid',
        body: 'Also valid body',
        channel: 'email',
        type: 'account_updated',
        metadata: { userId: 'user-1' },
      });

      // First and third should have been delivered
      expect(emailTransport.getSentEmails()).toHaveLength(2);

      // All three should be in history
      const logs = historyService.getAll();
      expect(logs).toHaveLength(3);
      expect(logs[0]!.status).toBe('sent');
      expect(logs[1]!.status).toBe('failed');
      expect(logs[2]!.status).toBe('sent');
    });
  });
});

