it('should maintain dispatch order for concurrent same-recipient dispatches', async () => {
  preferencesService.createPreferences({
    userId: 'user-1',
    sms: { enabled: true },
  });

  // Dispatch three SMS notifications concurrently using 'welcome' type
  // so body text appears in the rendered SMS template
  const p1 = notificationService.dispatch({
    recipient: '+15551234567',
    subject: 'First',
    body: 'AAA-first',
    channel: 'sms',
    type: 'welcome',
    metadata: { userId: 'user-1' },
  });
  const p2 = notificationService.dispatch({
    recipient: '+15551234567',
    subject: 'Second',
    body: 'BBB-second',
    channel: 'sms',
    type: 'welcome',
    metadata: { userId: 'user-1' },
  });
  const p3 = notificationService.dispatch({
    recipient: '+15551234567',
    subject: 'Third',
    body: 'CCC-third',
    channel: 'sms',
    type: 'welcome',
    metadata: { userId: 'user-1' },
